1	export const nextGeneration = (liveCells: number[][]): number[][] => {
2	  if (liveCells.length === 0) return [];
3	
4	  const liveSet = new Set(liveCells.map(c => c.join(",")));
5	
6	  const neighborCounts = new Map<string, number>();
7	
8	  for (const [x, y] of liveCells) {
9	    for (let dx = -1; dx <= 1; dx++) {
10	      for (let dy = -1; dy <= 1; dy++) {
11	        if (dx === 0 && dy === 0) continue;
12	        const key = `${x + dx},${y + dy}`;
13	        neighborCounts.set(key, (neighborCounts.get(key) ?? 0) + 1);
14	      }
15	    }
16	  }
17	
18	  const result: number[][] = [];
19	
20	  for (const [key, count] of neighborCounts) {
21	    if (count === 3 || (count === 2 && liveSet.has(key))) {
22	      result.push(key.split(",").map(Number));
23	    }
24	  }
25	
26	  return result;
27	};
